import { describe, it, expect } from "vitest";
import { step } from "./game-of-life.js";

describe("Game of Life", () => {
  it("should return empty set when given empty set of alive cells", () => {
    expect(step([])).toEqual([]);
  });
  it("should return empty set when a single cell dies from underpopulation", () => {
    expect(step([[0, 0]])).toEqual([]);
  });
  it("should keep a cell alive when it has exactly two neighbors", () => {
    // [1,1] has exactly 2 neighbors: [0,1] and [2,1]; those two each have only 1 neighbor so they die
    expect(step([[0, 1], [1, 1], [2, 1]])).toEqual([[1, 1]]);
  });
  it("should keep a cell alive when it has exactly three neighbors", () => {
    // 2x2 block: every cell has exactly 3 neighbors, all survive
    expect(step([[0, 0], [0, 1], [1, 0], [1, 1]])).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
  });
  it("should birth a new cell when a dead cell has exactly three neighbors", () => {
    // L-shape: [0,0],[1,0],[0,1] all survive (2 neighbors each); dead cell [1,1] has 3 neighbors → born
    expect(step([[0, 0], [1, 0], [0, 1]])).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
  });
  it.todo("should kill a cell that has more than three neighbors (overpopulation)");
  it.todo("should advance zero steps and return cells unchanged");
  it.todo("should correctly evolve a blinker pattern over one step");
  it.todo("should correctly evolve a blinker pattern over two steps (returning to original)");
  it.todo("should return alive cells sorted by x ascending then y ascending");
});

const cellKey = (x: number, y: number): string => `${x},${y}`;

export const step = (aliveCells: [number, number][]): [number, number][] => {
  const alive = new Set(aliveCells.map(([x, y]) => cellKey(x, y)));

  const neighborCount = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (alive.has(cellKey(x + dx, y + dy))) count++;
      }
    }
    return count;
  };

  const survivors = aliveCells.filter(([x, y]) => {
    const neighbors = neighborCount(x, y);
    return neighbors === 2 || neighbors === 3;
  });

  const candidates = new Set<string>();
  for (const [x, y] of aliveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = cellKey(x + dx, y + dy);
        if (!alive.has(key)) candidates.add(key);
      }
    }
  }

  const born: [number, number][] = [];
  for (const key of candidates) {
    const [cx, cy] = key.split(",").map(Number) as [number, number];
    if (neighborCount(cx, cy) === 3) born.push([cx, cy]);
  }

  return [...survivors, ...born];
};

