### Step 1: Naming Evaluation

**Naming Evaluation**:
- `step` ✅ Keep — domain-correct
- `cellKey` ✅ Keep — clear encoding helper
- `alive` ✅ Keep — Set of living cell keys
- `neighborCount` ✅ Keep — counts alive neighbors
- `survivors` ✅ Keep — cells that pass survival rule
- `candidates` ✅ Keep — dead cells adjacent to alive cells
- `born` ✅ Keep — newly birthed cells
- No naming changes needed.

### Step 2: Calculate Initial APP Mass

Current code (unchanged from last refactor):
```typescript
const cellKey = (x: number, y: number): string => `${x},${y}`;

export const step = (aliveCells: [number, number][]): [number, number][] => {
  const alive = new Set(aliveCells.map(([x, y]) => cellKey(x, y)));

  const neighborCount = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (alive.has(cellKey(x + dx, y + dy))) count++;
      }
    }
    return count;
  };

  const survivors = aliveCells.filter(([x, y]) => {
    const neighbors = neighborCount(x, y);
    return neighbors === 2 || neighbors === 3;
  });

  const candidates = new Set<string>();
  for (const [x, y] of aliveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = cellKey(x + dx, y + dy);
        if (!alive.has(key)) candidates.add(key);
      }
    }
  }

  const born: [number, number][] = [];
  for (const key of candidates) {
    const [x, y] = key.split(",").map(Number) as [number, number];
    if (neighborCount(x, y) === 3) born.push([x, y]);
  }

  return [...survivors, ...born].sort(([ax, ay], [bx, by]) => ax !== bx ? ax - bx : ay - by);
